import React from 'react';

const Navbar = () => {
  return (
    <nav className="flex items-center justify-between px-10 py-5 bg-white shadow-sm">
      <div className="flex items-center gap-2">
        <div className="bg-green-600 p-2 rounded-lg text-white font-bold">K</div>
        <span className="text-2xl font-bold text-gray-800 italic">kari.</span>
      </div>
      <div className="hidden md:flex gap-8 text-gray-600 font-medium">
        <a href="#" className="hover:text-green-600">About Us</a>
        <a href="#" className="hover:text-green-600">Freelancer</a>
        <a href="#" className="hover:text-green-600">Ad Page</a>
        <a href="#" className="hover:text-green-600">Explore Plan</a>
      </div>
      <button className="bg-black text-white px-6 py-2 rounded-full font-medium hover:bg-gray-800">
        Post Companies
      </button>
    </nav>
  );
};

export default Navbar;
